import React from 'react';
import { Menu, X, User, LogIn } from 'lucide-react';
import { Link } from 'react-router-dom';

interface NavbarProps {
  isLoggedIn?: boolean;
}

const Navbar: React.FC<NavbarProps> = ({ isLoggedIn = false }) => {
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);

  return (
    <header className="bg-white shadow-sm sticky top-0 z-50">
      <div className="container mx-auto px-4 py-4">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center">
              <span className="text-white font-bold text-xl">C</span>
            </div>
            <h1 className="text-2xl font-bold text-gray-900">CourtCraft</h1>
          </Link>

          {/* Desktop Navigation */}
          <nav className="hidden md:flex space-x-8">
            <Link to="/" className="text-gray-700 hover:text-indigo-600 font-medium">Home</Link>
            <Link to="/scenarios" className="text-gray-700 hover:text-indigo-600 font-medium">Scenarios</Link>
            <Link to="/marketplace" className="text-gray-700 hover:text-indigo-600 font-medium">Marketplace</Link>
            <Link to="/dashboard" className="text-gray-700 hover:text-indigo-600 font-medium">Dashboard</Link>
            <Link to="/multiplayer" className="text-gray-700 hover:text-indigo-600 font-medium">Multiplayer</Link>
            <Link to="/about" className="text-gray-700 hover:text-indigo-600 font-medium">About</Link>
            <Link to="/contact" className="text-gray-700 hover:text-indigo-600 font-medium">Contact</Link>
          </nav>

          <div className="hidden md:flex items-center space-x-4">
            {isLoggedIn ? (
              <div className="flex items-center space-x-2">
                <User className="w-5 h-5 text-gray-600" />
                <span className="text-gray-700">John Doe</span>
              </div>
            ) : (
              <>
                <Link to="/login" className="text-gray-700 hover:text-indigo-600 font-medium">Sign In</Link>
                <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                  Get Started
                </button>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <button 
            className="md:hidden text-gray-700"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>

        {/* Mobile Navigation */}
        {isMenuOpen && (
          <div className="md:hidden mt-4 py-4 border-t">
            <nav className="flex flex-col space-y-4">
              <Link to="/" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Home</Link>
              <Link to="/scenarios" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Scenarios</Link>
              <Link to="/marketplace" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Marketplace</Link>
              <Link to="/dashboard" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Dashboard</Link>
              <Link to="/multiplayer" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Multiplayer</Link>
              <Link to="/about" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>About</Link>
              <Link to="/contact" className="text-gray-700 hover:text-indigo-600 font-medium" onClick={() => setIsMenuOpen(false)}>Contact</Link>
            </nav>
            <div className="mt-6 flex flex-col space-y-3">
              {isLoggedIn ? (
                <div className="flex items-center space-x-2">
                  <User className="w-5 h-5 text-gray-600" />
                  <span className="text-gray-700">John Doe</span>
                </div>
              ) : (
                <>
                  <Link to="/login" className="text-gray-700 hover:text-indigo-600 font-medium py-2" onClick={() => setIsMenuOpen(false)}>Sign In</Link>
                  <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                    Get Started
                  </button>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </header>
  );
};

export default Navbar;
